import { useState, useEffect } from "react";
import { supabase } from "./supabaseClient";

const LOGO_W = "data:image/png;base64,";
const LOGO_B = "data:image/png;base64,";

const C = {
  bg:"#0A0A0F",surface:"#13131A",border:"#2A2A38",
  gold:"#F5C518",coral:"#FF4D6A",text:"#F0F0F8",
  muted:"#8888AA",dim:"#555570",green:"#00D48A",purple:"#9B59FF",
};

const css = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;500;600;700&display=swap');
  *{box-sizing:border-box;margin:0;padding:0;}
  body{background:${C.bg};color:${C.text};font-family:'Inter',system-ui,sans-serif;}
  ::-webkit-scrollbar{width:6px;}::-webkit-scrollbar-track{background:${C.surface};}::-webkit-scrollbar-thumb{background:${C.border};border-radius:3px;}
  input,textarea,select{background:${C.bg};color:${C.text};border:1px solid ${C.border};border-radius:8px;padding:10px 14px;font-size:14px;font-family:inherit;width:100%;outline:none;transition:border-color 0.2s;}
  input:focus,textarea:focus,select:focus{border-color:${C.gold};}
  button{cursor:pointer;font-family:inherit;}
  @keyframes eq1{0%,100%{height:8px}50%{height:22px}}@keyframes eq2{0%,100%{height:18px}50%{height:8px}}@keyframes eq3{0%,100%{height:12px}50%{height:28px}}@keyframes eq4{0%,100%{height:22px}50%{height:10px}}@keyframes eq5{0%,100%{height:6px}50%{height:20px}}
  @keyframes slideIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
  @keyframes spin{to{transform:rotate(360deg)}}
`;

const fmt$ = n => "$"+Number(n).toLocaleString("en-AU",{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtD = d => d?new Date(d).toLocaleDateString("en-AU",{day:"2-digit",month:"2-digit",year:"numeric"}):"";
const fmtDL = d => d?new Date(d).toLocaleDateString("en-AU",{day:"numeric",month:"long",year:"numeric"}):"";
const sCol = s=>({Confirmed:C.green,Lead:C.purple,Inquiry:C.gold,Paid:C.green,Sent:C.gold,Overdue:C.coral,Draft:C.muted,Opportunity:C.purple,Completed:C.muted}[s]||C.muted);

const Card=({children,style={}})=><div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:20,...style}}>{children}</div>;
const Btn=({children,variant="primary",onClick,style={},disabled=false})=>{
  const v={primary:{background:C.gold,color:"#000",fontWeight:700,border:"none"},danger:{background:C.coral,color:"#fff",fontWeight:700,border:"none"},ghost:{background:"transparent",color:C.text,border:`1px solid ${C.border}`},outline:{background:"transparent",color:C.gold,border:`1px solid ${C.gold}`},green:{background:C.green,color:"#000",fontWeight:700,border:"none"}};
  return <button onClick={onClick} disabled={disabled} style={{...v[variant],borderRadius:8,padding:"9px 18px",fontSize:14,opacity:disabled?0.5:1,...style}}>{children}</button>;
};
const Badge=({label,color})=><span style={{background:color+"22",color,border:`1px solid ${color}44`,borderRadius:6,padding:"3px 10px",fontSize:12,fontWeight:600,whiteSpace:"nowrap"}}>{label}</span>;
const EQBars=()=><div style={{display:"flex",alignItems:"flex-end",gap:3,height:28}}>{[1,2,3,4,5].map(i=><div key={i} style={{width:4,borderRadius:2,background:C.gold,animation:`eq${i} ${0.6+i*0.15}s ease-in-out infinite`}}/>)}</div>;
const LogoW=({height=36})=><img src={LOGO_W} alt="C-RAM Entertainment" style={{height,objectFit:"contain",display:"block"}}/>;
const LogoB=({height=36})=><img src={LOGO_B} alt="C-RAM Entertainment" style={{height,objectFit:"contain",display:"block"}}/>;

// ── PACKAGES ─────────────────────────────────────────────────────
const PACKAGES=[
  {id:"essential",name:"THE ESSENTIAL",tagline:"Everything you need to fill the floor",price:2200,exGST:2000,tag:null,accentColor:C.muted,borderColor:C.border,hours:"5 Hours",
   includes:[{name:"5-hour set",detail:"11pm cut-off"},{name:"DJ podium booth",detail:"Clean, professional setup"},{name:"DJ controller decks",detail:"Pro-grade gear"},{name:"Speakers",detail:"Up to 150 indoor / 100 outdoor"},{name:"4 party lights",detail:"To build the atmosphere"},{name:"Wireless microphone",detail:"Speeches & announcements"}],
   excludes:["Extra lighting tubes","Haze machine","Cocktail set","Turntables & mixer","Moving heads"],cta:"Book Essential"},
  {id:"signature",name:"THE SIGNATURE",tagline:"Next-level lighting & atmosphere",price:3400,exGST:3090.91,tag:"MOST POPULAR",accentColor:C.gold,borderColor:C.gold,hours:"5 Hours",
   includes:[{name:"5-hour set",detail:"11pm cut-off"},{name:"DJ podium booth",detail:"Clean, professional setup"},{name:"DJ controller decks",detail:"Pro-grade gear"},{name:"Speakers",detail:"Up to 150 indoor / 100 outdoor"},{name:"4 party lights",detail:"To build the atmosphere"},{name:"4 extra lighting tubes",detail:"All lighting synced to the music"},{name:"Haze machine",detail:"Where the venue allows"},{name:"Wireless microphone",detail:"Speeches & announcements"}],
   excludes:["Cocktail set","Turntables & mixer","Moving heads"],cta:"Book Signature"},
  {id:"premium",name:"THE PREMIUM",tagline:"The full show — turntables, cocktail set & moving heads",price:4800,exGST:4363.64,tag:"FULL PRODUCTION",accentColor:C.coral,borderColor:C.coral,hours:"2hr cocktail + 5hr set",
   includes:[{name:"2-hour cocktail set",detail:"Battery setup — plays anywhere"},{name:"5-hour main set",detail:"11pm cut-off"},{name:"DJ podium booth",detail:"Clean, professional setup"},{name:"2 turntable controllers + DJ mixer",detail:"Authentic old-school look"},{name:"Speakers",detail:"Up to 150 indoor / 100 outdoor"},{name:"4 party lights + 4 light tubes",detail:"Synced to the music"},{name:"2 moving heads",detail:"Adds dimension to the party"},{name:"Haze machine",detail:"Where the venue allows"},{name:"Wireless microphone",detail:"Speeches & announcements"}],
   excludes:[],cta:"Book Premium"},
];

const DEFAULT_BIZ={name:"C-RAM Entertainment",abn:"",address:"Melbourne, VIC 3000",phone:"0432 775 402",email:"djc.ram.bookings@gmail.com",website:"c-rament.com.au",bsb:"",account:"",accountName:"C-RAM Entertainment",bank:"",instagram:"@djc_ram",mixcloud:"mixcloud.com/DJC_RAM"};

const OCCASIONS = ["Birthday Party","Wedding","Corporate","Engagement","Other"];

function GetInTouch({biz, onSubmitLead, embedded=false}) {
  const blank = {name:"",email:"",phone:"",location:"",people:"",eventDate:"",occasion:"",service:"",message:""};
  const [form, setForm] = useState(blank);
  const [status, setStatus] = useState("idle"); // idle | sending | sent | error
  const [errorMsg, setErrorMsg] = useState("");
  const set = (k,v) => setForm(f => ({...f,[k]:v}));

  const required = ["name","email","phone","location","people","eventDate","occasion","service","message"];

  const buildText = () =>
`New website enquiry

Name: ${form.name}
Email: ${form.email}
Phone: ${form.phone}
Event location: ${form.location}
Guests: ${form.people}
Event date: ${form.eventDate ? fmtDL(form.eventDate) : ""}
Occasion: ${form.occasion}
Service / Package: ${form.service}

Message:
${form.message}`;

  const submit = async () => {
    const missing = required.filter(k => !String(form[k]).trim());
    if (missing.length) { setStatus("error"); setErrorMsg("Please fill in every field before sending."); return; }
    setStatus("sending"); setErrorMsg("");

    const matched = PACKAGES.find(p => form.service.startsWith(p.name));
    const lead = {
      id: Date.now(),
      name: form.name,
      type: form.occasion,
      phone: form.phone,
      email: form.email,
      status: "Inquiry",
      eventDate: form.eventDate,
      venue: form.location,
      notes: `Website enquiry · ${form.people} guests · Interested in: ${form.service}. "${form.message}"`,
      value: matched ? matched.price : 0,
      paid: 0,
      abn: "",
      source: "Website",
    };

    try {
      // Save the enquiry straight into the shared database. Because of the
      // security rules, anonymous visitors can ONLY insert an enquiry here —
      // it appears in the private hub's CRM as a new "Inquiry".
      const { error } = await supabase.from("clients").insert({
        name: lead.name,
        type: lead.type,
        phone: lead.phone,
        email: lead.email,
        status: "Inquiry",
        event_date: lead.eventDate || null,
        venue: lead.venue,
        notes: lead.notes,
        value: lead.value,
        paid: false,
        abn: "",
        source: "Website",
      });
      if (error) {
        setStatus("error");
        setErrorMsg("Sorry — something went wrong sending your enquiry. Please try again in a moment.");
        return;
      }
      setStatus("sent"); setForm(blank);
    } catch (e) {
      setStatus("error");
      setErrorMsg("Couldn't reach the server. Please check your connection and try again.");
    }
  };

  const lblStyle = {fontSize:11,fontWeight:600,letterSpacing:1,color:C.muted,textTransform:"uppercase",display:"block",marginBottom:6};
  const fieldStyle = {marginBottom:15};
  const siteNav = [["Home","https://c-rament.com.au"],["Our Services","https://c-rament.com.au/services/"],["Gallery","https://c-rament.com.au/gallery/"],["Get in touch","https://c-rament.com.au/get-in-touch/"]];
  const social = [["Facebook","https://www.facebook.com/DJC.RAMOFFICIAL"],["Instagram","https://www.instagram.com/djc_ram"],["YouTube","https://www.youtube.com/watch?v=9Jyj007h_m0"]];

  return (
    <div style={{minHeight: embedded?"auto":"100vh", background:C.bg, display:"flex", flexDirection:"column"}}>
      {!embedded && (
        <header style={{background:C.surface,borderBottom:`1px solid ${C.border}`,padding:"12px 18px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}><EQBars/><LogoW height={32}/></div>
          <nav style={{display:"flex",gap:4,flexWrap:"wrap"}}>
            {siteNav.map(([t,href]) => (
              <a key={t} href={href} style={{color:t==="Get in touch"?C.gold:C.muted,textDecoration:"none",fontSize:13,fontWeight:t==="Get in touch"?700:500,padding:"6px 10px"}}>{t}</a>
            ))}
          </nav>
        </header>
      )}

      <div style={{flex:1,width:"100%",maxWidth:620,margin:"0 auto",padding:embedded?"2px 0 0":"30px 16px"}}>
        <div style={{textAlign:"center",marginBottom:22}}>
          <h1 style={{fontFamily:"Bebas Neue,sans-serif",fontSize:embedded?32:46,letterSpacing:3,color:C.text,lineHeight:1}}>GET IN TOUCH</h1>
          <p style={{color:C.muted,fontSize:14,marginTop:8}}>Tell us about your event and we'll get the party planned.</p>
        </div>

        {status==="sent" ? (
          <Card style={{textAlign:"center",padding:"38px 22px"}}>
            <div style={{fontSize:42,marginBottom:10}}>🎉</div>
            <h3 style={{fontFamily:"Bebas Neue,sans-serif",fontSize:28,letterSpacing:1,color:C.green}}>Enquiry sent!</h3>
            <p style={{color:C.muted,fontSize:14,marginTop:8,lineHeight:1.5}}>Thanks — we've got your details and will be in touch shortly.</p>
            <div style={{marginTop:18}}><Btn variant="outline" onClick={() => setStatus("idle")}>Send another</Btn></div>
          </Card>
        ) : (
          <Card>
            {[["name","Name","text","Your full name"],["email","Email","email","you@email.com"],["phone","Phone","tel","04xx xxx xxx"],["location","Event Location","text","Venue or suburb"],["people","Number of People Attending","number","e.g. 120"],["eventDate","Event Date","date",""]].map(([k,lbl,type,ph]) => (
              <div key={k} style={fieldStyle}>
                <label style={lblStyle}>{lbl} *</label>
                <input type={type} value={form[k]} placeholder={ph} onChange={e => set(k,e.target.value)} />
              </div>
            ))}

            <div style={fieldStyle}>
              <label style={lblStyle}>Occasion *</label>
              <select value={form.occasion} onChange={e => set("occasion",e.target.value)}>
                <option value="">Select an occasion…</option>
                {OCCASIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div style={fieldStyle}>
              <label style={lblStyle}>Service / Package *</label>
              <select value={form.service} onChange={e => set("service",e.target.value)}>
                <option value="">Select a package…</option>
                {PACKAGES.map(p => <option key={p.id} value={`${p.name} — ${fmt$(p.price)}`}>{p.name} — {fmt$(p.price)}{p.tag ? ` · ${p.tag}` : ""}</option>)}
                <option value="Not sure yet — please recommend">Not sure yet — please recommend</option>
              </select>
            </div>

            <div style={fieldStyle}>
              <label style={lblStyle}>Message *</label>
              <textarea rows={5} value={form.message} placeholder="Tell us about your event…" onChange={e => set("message",e.target.value)} style={{resize:"vertical"}} />
            </div>

            {status==="error" && <div style={{background:C.coral+"22",color:C.coral,border:`1px solid ${C.coral}55`,borderRadius:8,padding:"10px 12px",fontSize:13,marginBottom:14,lineHeight:1.5}}>{errorMsg}</div>}

            <Btn onClick={submit} disabled={status==="sending"} style={{width:"100%",padding:"13px 0",fontSize:15,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
              {status==="sending" ? <><span style={{width:14,height:14,border:"2px solid #000",borderTopColor:"transparent",borderRadius:"50%",animation:"spin 0.7s linear infinite",display:"inline-block"}} /> Sending…</> : "Send Enquiry"}
            </Btn>

            <div style={{display:"flex",justifyContent:"center",gap:18,marginTop:18}}>
              {social.map(([t,href]) => (
                <a key={t} href={href} target="_blank" rel="noopener noreferrer" style={{color:C.muted,textDecoration:"none",fontSize:13}}>{t}</a>
              ))}
            </div>
            {!biz.email && <p style={{textAlign:"center",fontSize:11,color:C.coral,marginTop:10}}>Set your business email in Settings so enquiries reach you.</p>}
          </Card>
        )}
      </div>
    </div>
  );
}

