// ── APP (public website) ───────────────────────────
export default function App() {
  const pathToRoute = () => {
    const p = window.location.pathname.toLowerCase();
    if (p.includes("service")) return "services";
    if (p.includes("gallery")) return "gallery";
    if (p.includes("contact") || p.includes("enquir") || p.includes("get-in-touch")) return "contact";
    return "home";
  };
  const [route, setRoute] = useState(pathToRoute());
  const navigate = (r) => {
    const paths = { home: "/", services: "/services", gallery: "/gallery", contact: "/get-in-touch" };
    window.history.pushState({}, "", paths[r] || "/");
    setRoute(r);
    window.scrollTo(0, 0);
  };
  useEffect(() => {
    const onPop = () => setRoute(pathToRoute());
    window.addEventListener("popstate", onPop);
    return () => window.removeEventListener("popstate", onPop);
  }, []);
  return (
    <PublicShell route={route} navigate={navigate}>
      {route === "home" && <Home navigate={navigate} />}
      {route === "services" && <Services navigate={navigate} />}
      {route === "gallery" && <Gallery navigate={navigate} />}
      {route === "contact" && <GetInTouch biz={DEFAULT_BIZ} embedded={true} />}
    </PublicShell>
  );
}
